UPDATE event.notice
SET  title          = #{title}
    ,content        = #{content}
    ,top_yn         = #{topYn}
    ,use_yn         = #{useYn}
    ,file_seq       = #{fileSeq}
    ,updated_by     = #{uptUserSeq}
    ,updated_at     = CURRENT_TIMESTAMP
WHERE notice_seq = #{noticeSeq}
  AND deleted_at IS NULL
